struct CustomTex { uint32_t* pixels = nullptr; int w = 0, h = 0; };
static CustomTex g_Logo;
static ImTextureID g_LogoID = (ImTextureID)(intptr_t)0x1000;

static void GenerateCelticKnot(CustomTex& tex, int size) {
    delete[] tex.pixels;
    tex.w = tex.h = size;
    tex.pixels = new uint32_t[size * size]{};
    float cx = size * 0.5f, cy = size * 0.5f;
    float outerR = size * 0.43f, innerR = size * 0.12f;
    float bandW = size * 0.065f;
    for (int y = 0; y < size; y++) {
        for (int x = 0; x < size; x++) {
            float dx = x - cx, dy = y - cy;
            float dist = sqrtf(dx * dx + dy * dy);
            float a = atan2f(dy, dx);
            float ring = fabsf(dist - outerR);
            float alp = 0.0f;
            // Outer ring
            if (ring < bandW) alp = 1.0f - ring / bandW;
            // Inner triquetra: 3 overlapping arcs
            for (int i = 0; i < 3; i++) {
                float angle = a + i * 6.2832f / 3.0f;
                float tx = cx + innerR * cosf(angle);
                float ty = cy + innerR * sinf(angle);
                float adx = x - tx, ady = y - ty;
                float adist = sqrtf(adx * adx + ady * ady);
                float arcR = outerR * 0.55f;
                float aring = fabsf(adist - arcR);
                if (aring < bandW * 0.8f) {
                    float aa = 1.0f - aring / (bandW * 0.8f);
                    if (aa > alp) alp = aa;
                }
            }
            // Center dot
            float cdist = dist;
            if (cdist < bandW * 0.5f) {
                float ca = 1.0f - cdist / (bandW * 0.5f);
                if (ca > alp) alp = ca;
            }
            if (alp > 0.0f) {
                if (alp > 1.0f) alp = 1.0f;
                int a255 = (int)(alp * 230);
                tex.pixels[y * size + x] = ((uint32_t)a255 << 24) | 0xFFFFFF;
            }
        }
    }
}

void ImGui_ImplGDI_RenderDrawData(ImDrawData* draw_data, HWND hwnd) {
    RECT rect;
    GetClientRect(hwnd, &rect);
    int width = rect.right - rect.left;
    int height = rect.bottom - rect.top;
    if (width <= 0 || height <= 0) return;
    if (!g_Buffer || g_BufferWidth != width || g_BufferHeight != height) {
        delete[] g_Buffer;
        g_Buffer = new uint32_t[width * height]{};
        g_BufferWidth = width;
        g_BufferHeight = height;
    }
    memset(g_Buffer, 0, width * height * sizeof(uint32_t));

    if (draw_data && draw_data->CmdListsCount > 0) {
        ImGuiIO& io = ImGui::GetIO();
        const unsigned char* font_pixels = io.Fonts->TexPixelsAlpha8;
        int font_w = io.Fonts->TexWidth;
        int font_h = io.Fonts->TexHeight;
        bool has_font = (font_pixels != nullptr && font_w > 0 && font_h > 0);

        for (int n = 0; n < draw_data->CmdListsCount; n++) {
            const ImDrawList* cmd_list = draw_data->CmdLists[n];
            const ImDrawVert* vtx = cmd_list->VtxBuffer.Data;
            const ImDrawIdx* idx = cmd_list->IdxBuffer.Data;

            for (int cmd_i = 0; cmd_i < cmd_list->CmdBuffer.Size; cmd_i++) {
                const ImDrawCmd* pcmd = &cmd_list->CmdBuffer[cmd_i];
                if (pcmd->UserCallback) { pcmd->UserCallback(cmd_list, pcmd); continue; }

                // Clip rect com floor/ceil para nao perder pixels nas bordas
                int clip_x = (int)floorf(pcmd->ClipRect.x);
                int clip_y = (int)floorf(pcmd->ClipRect.y);
                int clip_x2 = (int)ceilf(pcmd->ClipRect.z);
                int clip_y2 = (int)ceilf(pcmd->ClipRect.w);
                if (clip_x < 0) clip_x = 0;
                if (clip_y < 0) clip_y = 0;
                if (clip_x2 > width) clip_x2 = width;
                if (clip_y2 > height) clip_y2 = height;
                int clip_w = clip_x2 - clip_x;
                int clip_h = clip_y2 - clip_y;
                if (clip_w <= 0 || clip_h <= 0) continue;

                unsigned int start = pcmd->IdxOffset;
                unsigned int end = start + pcmd->ElemCount;
                for (unsigned int i = start; i < end; i += 3) {
                    const ImDrawVert& va = vtx[idx[i]];
                    const ImDrawVert& vb = vtx[idx[i + 1]];
                    const ImDrawVert& vc = vtx[idx[i + 2]];

                    float min_x_f = fminf(va.pos.x, fminf(vb.pos.x, vc.pos.x));
                    float max_x_f = fmaxf(va.pos.x, fmaxf(vb.pos.x, vc.pos.x));
                    float min_y_f = fminf(va.pos.y, fminf(vb.pos.y, vc.pos.y));
                    float max_y_f = fmaxf(va.pos.y, fmaxf(vb.pos.y, vc.pos.y));

                    int min_x = max(clip_x, (int)floorf(min_x_f));
                    int max_x = min(clip_x2 - 1, (int)ceilf(max_x_f) - 1);
                    int min_y = max(clip_y, (int)floorf(min_y_f));
                    int max_y = min(clip_y2 - 1, (int)ceilf(max_y_f) - 1);
                    if (min_x > max_x || min_y > max_y) continue;

                    float area = edgeFunc(va.pos, vb.pos, vc.pos);
                    if (fabsf(area) < 0.001f) continue;
                    float inv_area = 1.0f / area;
                    bool ccw = area > 0.0f;

                    for (int y = min_y; y <= max_y; y++) {
                        for (int x = min_x; x <= max_x; x++) {
                            ImVec2 p((float)x + 0.5f, (float)y + 0.5f);
                            float w0 = edgeFunc(vb.pos, vc.pos, p);
                            float w1 = edgeFunc(vc.pos, va.pos, p);
                            float w2 = edgeFunc(va.pos, vb.pos, p);
                            if (ccw) { if (w0 < 0 || w1 < 0 || w2 < 0) continue; }
                            else      { if (w0 > 0 || w1 > 0 || w2 > 0) continue; }
                            w0 *= inv_area; w1 *= inv_area; w2 *= inv_area;

                            ImU32 c0 = va.col, c1 = vb.col, c2 = vc.col;
                            int r = (int)(((c0 >> IM_COL32_R_SHIFT) & 0xFF) * w0 + ((c1 >> IM_COL32_R_SHIFT) & 0xFF) * w1 + ((c2 >> IM_COL32_R_SHIFT) & 0xFF) * w2);
                            int g = (int)(((c0 >> IM_COL32_G_SHIFT) & 0xFF) * w0 + ((c1 >> IM_COL32_G_SHIFT) & 0xFF) * w1 + ((c2 >> IM_COL32_G_SHIFT) & 0xFF) * w2);
                            int b = (int)(((c0 >> IM_COL32_B_SHIFT) & 0xFF) * w0 + ((c1 >> IM_COL32_B_SHIFT) & 0xFF) * w1 + ((c2 >> IM_COL32_B_SHIFT) & 0xFF) * w2);
                            int a = (int)(((c0 >> IM_COL32_A_SHIFT) & 0xFF) * w0 + ((c1 >> IM_COL32_A_SHIFT) & 0xFF) * w1 + ((c2 >> IM_COL32_A_SHIFT) & 0xFF) * w2);

                            if (pcmd->TextureId == g_LogoID && g_Logo.pixels) {
                                float u = va.uv.x * w0 + vb.uv.x * w1 + vc.uv.x * w2;
                                float v = va.uv.y * w0 + vb.uv.y * w1 + vc.uv.y * w2;
                                int tx = (int)(u * g_Logo.w);
                                int ty = (int)(v * g_Logo.h);
                                if (tx >= 0 && tx < g_Logo.w && ty >= 0 && ty < g_Logo.h) {
                                    uint32_t lp = g_Logo.pixels[ty * g_Logo.w + tx];
                                    int lr = (lp >> 16) & 0xFF, lg = (lp >> 8) & 0xFF, lb = lp & 0xFF;
                                    int la = (lp >> 24) & 0xFF;
                                    r = (r * la) / 255; g = (g * la) / 255; b = (b * la) / 255;
                                    a = (a * la) / 255;
                                } else { a = 0; }
                            } else if (has_font) {
                                float u = va.uv.x * w0 + vb.uv.x * w1 + vc.uv.x * w2;
                                float v = va.uv.y * w0 + vb.uv.y * w1 + vc.uv.y * w2;
                                int tx = (int)(u * font_w);
                                int ty = (int)(v * font_h);
                                if (tx >= 0 && tx < font_w && ty >= 0 && ty < font_h) {
                                    a = (a * font_pixels[ty * font_w + tx]) / 255;
                                } else { a = 0; }
                            }
                            if (a <= 0) continue;
                            if (a > 255) a = 255;
                            if (r > 255) r = 255; if (g > 255) g = 255; if (b > 255) b = 255;

                            // Premultiplied alpha
                            uint32_t pm_a = a;
                            uint32_t pm_r = (uint32_t)r * a / 255;
                            uint32_t pm_g = (uint32_t)g * a / 255;
                            uint32_t pm_b = (uint32_t)b * a / 255;

                            int bi = y * width + x;
                            uint32_t dst = g_Buffer[bi];
                            uint32_t da = (dst >> 24) & 0xFF;
                            uint32_t dr = (dst >> 16) & 0xFF;
                            uint32_t dg = (dst >> 8) & 0xFF;
                            uint32_t db = dst & 0xFF;

                            uint32_t inv_a = 255 - pm_a;
                            uint32_t outa = da + pm_a - da * pm_a / 255; // correct union formula
                            uint32_t outr = dr * inv_a / 255 + pm_r;
                            uint32_t outg = dg * inv_a / 255 + pm_g;
                            uint32_t outb = db * inv_a / 255 + pm_b;

                            g_Buffer[bi] = (outa << 24) | (outr << 16) | (outg << 8) | outb;
                        }
                    }
                }
            }
        }
    }

    // Use UpdateLayeredWindow with per-pixel alpha
    HDC hdcScreen = GetDC(NULL);
    if (hdcScreen) {
        HDC hdcMem = CreateCompatibleDC(hdcScreen);
        if (hdcMem) {
            BITMAPV5HEADER bi = {0};
            bi.bV5Size = sizeof(BITMAPV5HEADER);
            bi.bV5Width = width;
            bi.bV5Height = -height;
            bi.bV5Planes = 1;
            bi.bV5BitCount = 32;
            bi.bV5Compression = BI_RGB;
            bi.bV5AlphaMask = 0xFF000000;

            void* bits = nullptr;
            HBITMAP hBitmap = CreateDIBSection(hdcScreen, (BITMAPINFO*)&bi, DIB_RGB_COLORS, &bits, NULL, 0);
            if (hBitmap) {
                SelectObject(hdcMem, hBitmap);
                memcpy(bits, g_Buffer, width * height * sizeof(uint32_t));

                SIZE sz = {width, height};
                POINT ptSrc = {0, 0};
                BLENDFUNCTION blend = { AC_SRC_OVER, 0, 255, AC_SRC_ALPHA };
                UpdateLayeredWindow(hwnd, hdcScreen, NULL, &sz, hdcMem, &ptSrc, 0, &blend, ULW_ALPHA);

                DeleteObject(hBitmap);
            }
            DeleteDC(hdcMem);
        }
        ReleaseDC(NULL, hdcScreen);
    }
}

void GUIParticles() {
    ImDrawList* drawList = ImGui::GetWindowDrawList();

    static const int numParticles = 115;
    static ImVec2 particlePositions[numParticles];
    static ImVec2 particleDistance;
    static ImVec2 particleVelocities[numParticles];

    static bool initialized = false;
    if (!initialized)
    {
        for (int i = 0; i < numParticles; ++i)
        {
            particlePositions[i] = ImVec2(
                ImGui::GetWindowPos().x + ImGui::GetWindowSize().x * static_cast<float>(rand()) / RAND_MAX,
                ImGui::GetWindowPos().y + ImGui::GetWindowSize().y * static_cast<float>(rand()) / RAND_MAX
            );

            particleVelocities[i] = ImVec2(
                static_cast<float>((rand() % 11) - 5),
                static_cast<float>((rand() % 11) - 5)
            );
        }

        initialized = true;
    }

    ImVec2 cursorPos = ImGui::GetIO().MousePos;

    for (int i = 0; i < numParticles; ++i) {
        for (int j = i + 1; j < numParticles; ++j) {
            float distance = std::hypotf(particlePositions[j].x - particlePositions[i].x, particlePositions[j].y - particlePositions[i].y);
            float opacity = 1.0f - (distance / 55.0f);  // opacity cahnge

            if (opacity > 0.0f) {
                ImU32 lineColor = ImGui::GetColorU32(ImVec4(ParticleColour[0], ParticleColour[1], ParticleColour[2], opacity));
                drawList->AddLine(particlePositions[i], particlePositions[j], lineColor);
            }
        }

        float distanceToCursor = std::hypotf(cursorPos.x - particlePositions[i].x, cursorPos.y - particlePositions[i].y);
        float opacityToCursor = 1.0f - (distanceToCursor / 52.0f);  // Adjust the divisor to control the opacity change

        if (opacityToCursor > 0.0f) {
            ImU32 lineColorToCursor = ImGui::GetColorU32(ImVec4(ParticleColour[0], ParticleColour[1], ParticleColour[2], opacityToCursor));
            drawList->AddLine(cursorPos, particlePositions[i], lineColorToCursor);
        }
    }

    float deltaTime = ImGui::GetIO().DeltaTime;
    for (int i = 0; i < numParticles; ++i) {
        particlePositions[i].x += particleVelocities[i].x * deltaTime * 5.5f;  // Adjust the speed multiplier
        particlePositions[i].y += particleVelocities[i].y * deltaTime * 5.5f;

        if (particlePositions[i].x < ImGui::GetWindowPos().x)
            particlePositions[i].x = ImGui::GetWindowPos().x + ImGui::GetWindowSize().x;
        else if (particlePositions[i].x > ImGui::GetWindowPos().x + ImGui::GetWindowSize().x)
            particlePositions[i].x = ImGui::GetWindowPos().x;

        if (particlePositions[i].y < ImGui::GetWindowPos().y)
            particlePositions[i].y = ImGui::GetWindowPos().y + ImGui::GetWindowSize().y;
        else if (particlePositions[i].y > ImGui::GetWindowPos().y + ImGui::GetWindowSize().y)
            particlePositions[i].y = ImGui::GetWindowPos().y;

        ImU32 particleColour = ImGui::ColorConvertFloat4ToU32(Particle);

        drawList->AddCircleFilled(particlePositions[i], 0.4f, particleColour);
    }
}

